        for (int i = 0; i < N; i++) {

          for (int a = 0; a < k; a++) {

            for (int t = a + k; t < maxA; t += k) {

              available[i][a] |= available[i][t];

            }

          }

        }

      }

    }

    cout << res << endl;

  }

  return 0;

}

